/// Concrete [UserRepository] for the `users` tag.
///
/// Every method calls the generated data source inside `try/catch`, maps any
/// exception to a `Failure` via skill 15's `mapError`, maps the DTO to its
/// domain entity with `toEntity()`, and returns `Result<T>` — never throwing
/// across the layer line (CONVENTIONS §5).
final class UserRepositoryImpl implements UserRepository {
  /// Creates a [UserRepositoryImpl].
  const UserRepositoryImpl(this._remote);

  final UsersRemoteDataSource _remote;

  @override
  Future<Result<List<UserEntity>>> getUsers({int? page, int? perPage}) async {
    try {
      final dtos = await _remote.getUsers(page: page, perPage: perPage);
      return Ok(dtos.map((d) => d.toEntity()).toList());
    } on DioException catch (e, st) {
      return Err(mapError(e, st));
    } on Object catch (e, st) {
      return Err(mapError(e, st));
    }
  }

  @override
  Future<Result<UserEntity>> getUser(String id) async {
    try {
      final dto = await _remote.getUserById(id);
      return Ok(dto.toEntity());
    } on DioException catch (e, st) {
      return Err(mapError(e, st));
    } on Object catch (e, st) {
      return Err(mapError(e, st));
    }
  }

  @override
  Future<Result<UserEntity>> createUser(UserEntity user) async {
    try {
      // Map domain → DTO for the request body, then DTO → domain for the result.
      final body = UserDto(id: user.id, email: user.email);
      final dto = await _remote.createUser(body);
      return Ok(dto.toEntity());
    } on DioException catch (e, st) {
      return Err(mapError(e, st));
    } on Object catch (e, st) {
      return Err(mapError(e, st));
    }
  }
}

/// Binds the domain [UserRepository] interface to its implementation.
///
/// Downstream code depends on the *interface* type, so tests override this (or
/// `dioProvider`) with a fake via `ProviderScope(overrides:)` — DI chain is
/// dio → data source → repository (skill 11).
@riverpod
UserRepository userRepository(Ref ref) =>
    UserRepositoryImpl(ref.watch(usersRemoteDataSourceProvider));

