/// Domain contract for the `users` feature (normally in `domain/`).
abstract interface class UserRepository {
  /// Lists users.
  Future<Result<List<UserEntity>>> getUsers({int? page, int? perPage});

  /// Loads one user by id.
  Future<Result<UserEntity>> getUser(String id);

  /// Creates a user, returning the persisted entity.
  Future<Result<UserEntity>> createUser(UserEntity user);
}

/// Outcome wrapper — see CONVENTIONS §5. Owned by skill 15.
sealed class Result<T> {
  const Result();
}

/// Success carrying a [value].
final class Ok<T> extends Result<T> {
  /// Creates an [Ok].
  const Ok(this.value);

  /// The successful value.
  final T value;
}

/// Failure carrying a typed [failure].
final class Err<T> extends Result<T> {
  /// Creates an [Err].
  const Err(this.failure);

  /// The mapped failure.
  final Failure failure;
}

/// Typed failure base — owned by skill 15.
sealed class Failure {
  /// Creates a [Failure].
  const Failure(this.message);

  /// Developer-facing message (logs only).
  final String message;
}

/// Fallback failure used by the placeholder mapper below.
final class UnknownFailure extends Failure {
  /// Creates an [UnknownFailure].
  const UnknownFailure(super.message);
}

/// Placeholder for skill 15's `mapError`.
///
/// The real mapper translates `DioException` types into the right `Failure`
/// (timeout → `TimeoutFailure`, 401/403 → `UnauthorizedFailure`,
/// 404 → `NotFoundFailure`, no connection → `NetworkFailure`, …).
Failure mapError(Object error, StackTrace stackTrace) =>
    UnknownFailure(error.toString());
